Use ASP.NET Core's `WebApplicationFactory<T>` — it hosts your app in-process and gives you an `HttpClient` that talks to it without opening a real port.

**Setup:**

```csharp
// MyMcpTests.cs
using Microsoft.AspNetCore.Mvc.Testing;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsCall_ReturnsExpectedResult()
    {
        // Send initialize first, then call a tool
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.False(body.GetProperty("result")
                         .GetProperty("isError")
                         .GetBoolean());
    }
}
```

**Key points:**

- **No real port** — `WebApplicationFactory` uses an in-memory test server (`TestServer`)
- **Full pipeline** — middleware, routing, DI, and serialization all run exactly as in production
- **Mock services** — override DI registrations via `factory.WithWebApplicationFactory(b => b.ConfigureServices(...))` to swap in fakes
- **SSE transport** — if your server uses SSE, read the response stream with `ReadAsStreamAsync()` and parse `data:` lines
- **Stateful sessions** — if your server tracks sessions, reuse the same `HttpClient` instance across calls or pass session headers

This is the standard ASP.NET Core integration testing pattern — no special MCP tooling required.
